    const layoutMigrationSource = `
function moveLayoutItemToEnd(iids, iid) {
    if (!Array.isArray(iids) || !iid) return;
    const index = iids.indexOf(iid);
    if (index < 0 || index === iids.length - 1) return;
    const [item] = iids.splice(index, 1);
    iids.push(item);
}

function migrateFirstPageMusicToBottom(savedLayouts) {
    const pageLayout = Array.isArray(savedLayouts)
        ? savedLayouts.find(layoutData => layoutData && layoutData.cid === 'page-1' && Array.isArray(layoutData.iids))
        : null;
    if (!pageLayout) return;
    moveLayoutItemToEnd(pageLayout.iids, 'panel-music-player');
}

function migrateSecondPageAvatarDefaultLayout(savedLayouts) {
    const pageLayout = Array.isArray(savedLayouts)
        ? savedLayouts.find(layoutData => layoutData && layoutData.cid === 'page-2' && Array.isArray(layoutData.iids))
        : null;
    if (!pageLayout) return;

    const iids = pageLayout.iids;
    const oldDefaultIndex = iids.findIndex((iid, index) =>
        iid === 'panel-dreamy-card' &&
        iids[index + 1] === 'grid-page-2-1-block' &&
        iids[index + 2] === 'panel-dual-avatar' &&
        iids[index + 3] === 'panel-sun-card' &&
        iids[index + 4] === 'grid-page-2-2-block'
    );
    if (oldDefaultIndex < 0) return;

    const dualIndex = oldDefaultIndex + 2;
    const sunIndex = oldDefaultIndex + 3;
    [iids[dualIndex], iids[sunIndex]] = [iids[sunIndex], iids[dualIndex]];
}

if (typeof layoutUsesLegacyIds === 'function' && !layoutUsesLegacyIds.__rinnoDesktopHomeOrderFix) {
    const baseLayoutUsesLegacyIds = layoutUsesLegacyIds;
    layoutUsesLegacyIds = function(savedLayouts) {
        migrateFirstPageMusicToBottom(savedLayouts);
        migrateSecondPageAvatarDefaultLayout(savedLayouts);
        return baseLayoutUsesLegacyIds(savedLayouts);
    };
    layoutUsesLegacyIds.__rinnoDesktopHomeOrderFix = true;
}
`;

    const delegatedAppLauncherSource = `
function openDelegatedRinnoApp(name) {
    const lock = document.getElementById('lock-screen');
    if (lock && !lock.classList.contains('unlocked')) return false;
    const launchers = {
        letter: typeof openLetterApp === 'function' ? openLetterApp : null,
        settings: typeof openSettingsApp === 'function' ? openSettingsApp : null,
        style: typeof openStyleApp === 'function' ? openStyleApp : null,
        private: typeof openPrivateApp === 'function' ? openPrivateApp : null,
        prologue: typeof openPrologueApp === 'function' ? openPrologueApp : null,
        community: typeof openCommunityApp === 'function' ? openCommunityApp : null,
        encounter: typeof openEncounterApp === 'function' ? openEncounterApp : null,
        dossier: typeof openDossierApp === 'function' ? openDossierApp : null,
        wanye: typeof openWanyeApp === 'function' ? openWanyeApp : null,
        lingguang: typeof openLingguangApp === 'function' ? openLingguangApp : null,
        guide: typeof openGuideApp === 'function' ? openGuideApp : null,
        zhenxuan: typeof openZhenxuanApp === 'function' ? openZhenxuanApp : null,
        phone: typeof openPhoneApp === 'function' ? openPhoneApp : null,
        assets: typeof openAssetsApp === 'function' ? openAssetsApp : null
    };
    const launcher = launchers[name] || null;
    if (typeof launcher !== 'function') return false;
    launcher();
    return true;
}

function isDelegatedRinnoAppLaunchSuppressed() {
    const now = window.performance && typeof window.performance.now === 'function'
        ? window.performance.now()
        : Date.now();
    return now < (Number(window.__rinnoSuppressAppLaunchUntil) || 0);
}

document.addEventListener('click', function(event) {
    if (document.body.classList.contains('edit-mode')) return;
    if (isDelegatedRinnoAppLaunchSuppressed()) {
        event.preventDefault();
        event.stopImmediatePropagation();
        return;
    }
    const target = event.target instanceof Element ? event.target : event.target?.parentElement;
    if (target && document.getElementById('app-root')?.contains(target)) return;
    const launcher = target?.closest?.('[data-open-app]');
    if (!launcher || !document.body.contains(launcher)) return;
    if (openDelegatedRinnoApp(launcher.getAttribute('data-open-app') || '')) {
        event.preventDefault();
        event.stopPropagation();
    }
});
`;

    function stripDevServerInjection(text) {
        return String(text)
            .replace(/<!-- Code injected by live-server -->\s*<script\b[^>]*>[\s\S]*?<\/script>/g, '')
            .replace(/<script\b[^>]*>[\s\S]*?(?:refreshCSS|Live reload enabled|Live-Reloading)[\s\S]*?<\/script>/g, '')
            .replace(/<!-- Code injected by live-server -->\s*<script\b[^>]*>[\s\S]*$/g, '')
            .replace(/<script\b[^>]*>[\s\S]*?(?:refreshCSS|Live reload enabled|Live-Reloading)[\s\S]*$/g, '');
    }

    function normalizePrivateFragment(root) {
        const privateApp = root.querySelector?.('#private-app');
        if (!privateApp) return;
        const header = privateApp.querySelector('.private-chat-top');
        header?.querySelector('#private-chat-back')?.remove();
        header?.querySelector('#private-chat-avatar')?.remove();
        if (header) {
            let heading = header.querySelector('.private-chat-heading');
            if (!heading) {
                heading = document.createElement('div');
                heading.className = 'private-chat-heading';
                header.appendChild(heading);
            }
            heading.innerHTML = '<div class="private-chat-kicker">PRIVATE LINE</div><button class="private-chat-title interactive" id="private-chat-title" type="button" aria-label="返回主屏">PRIVATE</button><div class="private-chat-issue" id="private-chat-issue">把想说的话留到安静处慢慢展开。</div>';
        }
        const whisperPane = privateApp.querySelector('[data-private-panel="whisper"]');
        if (whisperPane && !whisperPane.querySelector('.private-whisper-section')) {
            whisperPane.innerHTML = '<section class="private-whisper-section" aria-label="消息"><div class="private-whisper-head"><div><div class="private-whisper-kicker">MESSAGES</div><h2 class="private-whisper-title">消息</h2></div><div class="private-whisper-count" id="private-thread-count">0 threads</div></div><div class="private-thread-list" id="private-thread-list" aria-label="消息列表"></div></section>';
        }
        const contactButtons = privateApp.querySelectorAll('.private-contact-filter button');
        if (contactButtons[0]) contactButtons[0].textContent = '近席';
        if (contactButtons[1]) contactButtons[1].textContent = '群像';
        const contactSearch = privateApp.querySelector('#private-message-search-input');
        if (contactSearch) contactSearch.placeholder = '检索暗号 / 关系札记';
        privateApp.querySelectorAll('.private-message-home, .private-quick-composer, .private-thread-card').forEach(el => el.remove());
    }

    
    function stripDevServerInjection(content) {
        return String(content ?? '')
            .replace(/^\uFEFF/, '')
            .replace(/<!--\s*Code injected by live-server\s*-->[\s\S]*?<!--\s*\/Code injected by live-server\s*-->/gi, '')
            .replace(/<script[^>]*src=["']\/?livereload[^"']*["'][^>]*><\/script>/gi, '')
            .replace(/<script[^>]*src=["']\/@vite\/client["'][^>]*><\/script>/gi, '')
            .replace(/<script\b[^>]*>[\s\S]*?(?:live-server|livereload|new\s+EventSource|new\s+WebSocket|__vite_plugin)[\s\S]*?<\/script>/gi, '');
    }

    async function fetchText(file, fallbacks = {}) {
        const hasFallback = Object.prototype.hasOwnProperty.call(fallbacks, file);
        if (window.location.protocol === 'file:' && hasFallback) {
            return stripDevServerInjection(fallbacks[file]);
        }

        try {
            const requestUrl = file.includes('?')
                ? `${file}&v=${RINNO_RUNTIME_BUILD}`
                : `${file}?v=${RINNO_RUNTIME_BUILD}`;
            const response = await fetch(requestUrl, { cache: 'no-cache' });
            if (!response.ok) throw new Error(file + ' (' + response.status + ')');
            return stripDevServerInjection(await response.text());
        } catch (error) {
            if (hasFallback) return stripDevServerInjection(fallbacks[file]);
            throw error;
        }
    }

    function escapeHtml(value) {
        return String(value).replace(/[&<>"]/g, char => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[char]));
    }

    function showBootError(error) {
        console.error('Rinno boot failed:', error);
        if (!appRoot) return;
        const message = error && error.message ? error.message : error;
        appRoot.innerHTML = '<section class="boot-error" role="alert"><h1>Rinno boot failed</h1><p>Open Rinno.html through a local web server. Direct file opening may block app fragment loading.</p><pre>' + escapeHtml(message) + '</pre></section>';
    }

    function normalizeStyleFragment(root) {
        const cover = root.querySelector?.('#style-app .style-cover');
        if (!cover) return;
        cover.className = 'style-cover';
        cover.removeAttribute('data-style-upload');
        cover.removeAttribute('role');
        cover.removeAttribute('tabindex');
        cover.removeAttribute('aria-label');
        cover.setAttribute('aria-hidden', 'true');
    }

    const privateMomentsCoverId = 'private_moments_cover_image';
    const privateMomentsCoverLocalKey = 'rinno:private:moments-cover';
    const privateCoverImageMaxEdge = 1280;
    const privateCoverImageQuality = 0.78;
    let privateMomentsCoverToneRequest = 0;

    function setPrivateMomentsCoverTone(tone = 'light') {
        const normalized = tone === 'dark' ? 'dark' : 'light';
        const nameColor = normalized === 'dark' ? '#fffdfd' : '#211c20';
        const signatureColor = normalized === 'dark' ? 'rgba(255, 253, 253, 0.78)' : 'rgba(33, 28, 32, 0.58)';
        document.querySelectorAll('.private-chat-screen').forEach(screen => {
            screen.setAttribute('data-private-moments-cover-tone', normalized);
        });
        document.querySelectorAll('.private-moments-me').forEach(identity => {
            identity.style.setProperty('--private-moments-name-color', nameColor);
            identity.style.setProperty('--private-moments-signature-color', signatureColor);
            identity.querySelector('.private-moments-name')?.style.setProperty('color', nameColor, 'important');
            identity.querySelector('.private-moments-signature')?.style.setProperty('color', signatureColor, 'important');
        });
    }

    function resolvePrivateMomentsCoverTone(content) {
        return new Promise(resolve => {
            if (!content) {
                resolve('light');
                return;
            }
            const image = new Image();
            if (!/^data:|^blob:/i.test(content)) image.crossOrigin = 'anonymous';
            image.onerror = () => resolve('dark');
            image.onload = () => {
                try {
                    const width = 96;
                    const height = 36;
                    const canvas = document.createElement('canvas');
                    canvas.width = width;
                    canvas.height = height;
                    const context = canvas.getContext('2d', { willReadFrequently: true });
                    if (!context) {
                        resolve('dark');
                        return;
                    }
                    const sourceWidth = image.naturalWidth || image.width;
                    const sourceHeight = image.naturalHeight || image.height;
                    if (!sourceWidth || !sourceHeight) {
                        resolve('dark');
                        return;
                    }
                    const scale = Math.max(width / sourceWidth, height / sourceHeight);
                    const drawWidth = sourceWidth * scale;
                    const drawHeight = sourceHeight * scale;
                    context.drawImage(image, (width - drawWidth) / 2, (height - drawHeight) / 2, drawWidth, drawHeight);

                    const sampleX = Math.round(width * 0.56);
                    const sampleY = Math.round(height * 0.62);
                    const sampleWidth = Math.round(width * 0.38);
                    const sampleHeight = Math.round(height * 0.32);
                    const pixels = context.getImageData(sampleX, sampleY, sampleWidth, sampleHeight).data;
                    let luminance = 0;
                    let count = 0;
                    for (let index = 0; index < pixels.length; index += 4) {
                        const alpha = pixels[index + 3] / 255;
                        if (alpha <= 0.02) continue;
                        const red = pixels[index];
                        const green = pixels[index + 1];
                        const blue = pixels[index + 2];
                        luminance += (0.2126 * red + 0.7152 * green + 0.0722 * blue) * alpha;
                        count += alpha;
                    }
                    const average = count ? luminance / count / 255 : 0.45;
                    resolve(average < 0.56 ? 'dark' : 'light');
                } catch (error) {
                    resolve('dark');
                }
            };
            image.src = content;
        });
    }

    async function updatePrivateMomentsCoverTone(content) {
        const requestId = ++privateMomentsCoverToneRequest;
        const tone = await resolvePrivateMomentsCoverTone(content);
        if (requestId !== privateMomentsCoverToneRequest) return;
        setPrivateMomentsCoverTone(tone);
    }

    function applyPrivateMomentsCoverImage(content) {
        document.querySelectorAll('.private-moments-cover').forEach(cover => {
            if (content) {
                cover.style.setProperty('background', `linear-gradient(180deg, rgba(24, 22, 25, 0.04), rgba(24, 22, 25, 0.12)), url("${content}") center center / cover no-repeat`, 'important');
                cover.classList.add('has-custom-cover');
            } else {
                cover.style.removeProperty('background');
                cover.classList.remove('has-custom-cover');
            }
        });
        updatePrivateMomentsCoverTone(content);
    }

    async function loadPrivateMomentsCoverImage() {
        let content = '';
        try {
            if (typeof db !== 'undefined' && db?.edits) {
                const saved = await db.edits.get(privateMomentsCoverId);
                content = String(saved?.content || '');
            }
        } catch (error) {
            console.warn('Private moments cover load skipped:', error);
        }
        if (!content) {
            try {
                content = window.localStorage?.getItem(privateMomentsCoverLocalKey) || '';
            } catch (error) {
                content = '';
            }
        }
        applyPrivateMomentsCoverImage(content);
    }

    async function savePrivateMomentsCoverImage(content) {
        try {
            window.localStorage?.setItem(privateMomentsCoverLocalKey, content);
        } catch (error) {
            console.warn('Private moments cover local fallback skipped:', error);
        }
        try {
            if (typeof db !== 'undefined' && db?.edits) {
                await db.edits.put({
                    id: privateMomentsCoverId,
                    content,
                    type: 'image'
                });
            }
        } catch (error) {
            console.warn('Private moments cover save skipped:', error);
        }
    }

    function normalizePrivateFragment(root = document) {
        const privateApp = root?.querySelector?.('#private-app');
        if (!privateApp) return;

        const title = privateApp.querySelector('#private-chat-title');
        if (title && !String(title.textContent || '').trim()) {
            title.textContent = 'PRIVATE';
        }

        const contactButtons = privateApp.querySelectorAll('.private-contact-filter button');
        if (contactButtons[0] && !/近席/.test(String(contactButtons[0].textContent || ''))) {
            contactButtons[0].textContent = '近席';
        }
        if (contactButtons[1] && !/群像/.test(String(contactButtons[1].textContent || ''))) {
            contactButtons[1].textContent = '群像';
        }

        const contactSearch = privateApp.querySelector('#private-message-search-input');
        if (contactSearch && !String(contactSearch.getAttribute('placeholder') || '').trim()) {
            contactSearch.setAttribute('placeholder', '检索暗号 / 关系札记');
        }

        privateApp.querySelectorAll('.private-message-home, .private-quick-composer').forEach(node => node.remove());
    }

    function readPrivateCoverBlobAsDataUrl(file) {
        return new Promise((resolve, reject) => {
            if (!file) {
                resolve('');
                return;
            }
            const reader = new FileReader();
            reader.onerror = () => reject(reader.error);
            reader.onload = () => resolve(String(reader.result || ''));
            reader.readAsDataURL(file);
        });
    }

    function readPrivateCoverFile(file) {
        if (!file) return Promise.resolve('');
        const fileType = String(file.type || '').toLowerCase();
        if (!fileType.startsWith('image/') || fileType.includes('svg')) {
            return readPrivateCoverBlobAsDataUrl(file);
        }
        return new Promise((resolve, reject) => {
            const objectUrl = URL.createObjectURL(file);
            const image = new Image();
            image.decoding = 'async';
            image.onerror = () => {
                URL.revokeObjectURL(objectUrl);
                readPrivateCoverBlobAsDataUrl(file).then(resolve, reject);
            };
            image.onload = () => {
                try {
                    const sourceWidth = image.naturalWidth || image.width;
                    const sourceHeight = image.naturalHeight || image.height;
                    if (!sourceWidth || !sourceHeight) {
                        URL.revokeObjectURL(objectUrl);
                        readPrivateCoverBlobAsDataUrl(file).then(resolve, reject);
                        return;
                    }
                    const sourceEdge = Math.max(sourceWidth, sourceHeight);
                    if (sourceEdge <= privateCoverImageMaxEdge && file.size <= 450000) {
                        URL.revokeObjectURL(objectUrl);
                        readPrivateCoverBlobAsDataUrl(file).then(resolve, reject);
                        return;
                    }
                    const scale = Math.min(1, privateCoverImageMaxEdge / sourceEdge);
                    const width = Math.max(1, Math.round(sourceWidth * scale));
                    const height = Math.max(1, Math.round(sourceHeight * scale));
                    const canvas = document.createElement('canvas');
                    canvas.width = width;
                    canvas.height = height;
                    const context = canvas.getContext('2d', { alpha: false });
                    if (!context) throw new Error('Canvas unavailable.');
                    context.fillStyle = '#fff';
                    context.fillRect(0, 0, width, height);
                    context.drawImage(image, 0, 0, width, height);
                    const finish = blob => {
                        URL.revokeObjectURL(objectUrl);
                        if (blob) {
                            readPrivateCoverBlobAsDataUrl(blob).then(resolve, reject);
                            return;
                        }
                        resolve(canvas.toDataURL('image/jpeg', privateCoverImageQuality));
                    };
                    if (canvas.toBlob) canvas.toBlob(finish, 'image/jpeg', privateCoverImageQuality);
                    else finish(null);
                } catch (error) {
                    URL.revokeObjectURL(objectUrl);
                    readPrivateCoverBlobAsDataUrl(file).then(resolve, reject);
                }
            };
            image.src = objectUrl;
        });
    }

    function getPrivateMomentsCoverInput() {
        let input = document.getElementById('private-moments-cover-input');
        if (input) return input;
        input = document.createElement('input');
        input.id = 'private-moments-cover-input';
        input.type = 'file';
        input.accept = 'image/*';
        input.hidden = true;
        input.addEventListener('change', async event => {
            const file = event.target.files?.[0];
            event.target.value = '';
            if (!file) return;
            try {
                const content = await readPrivateCoverFile(file);
                if (!content) return;
                applyPrivateMomentsCoverImage(content);
                await savePrivateMomentsCoverImage(content);
                if (typeof showPrivateSystemToast === 'function') showPrivateSystemToast('朋友圈背景图已保存。');
            } catch (error) {
                console.error('Private moments cover update failed:', error);
                if (typeof showPrivateSystemToast === 'function') showPrivateSystemToast('背景图保存失败，请换一张图片。');
            }
        });
        document.body.appendChild(input);
        return input;
    }

    function enhancePrivateMomentsCover(root = document) {
        root.querySelectorAll?.('.private-moments-cover').forEach(cover => {
            if (cover.dataset.coverUploadReady === 'true') return;
            cover.dataset.coverUploadReady = 'true';
            cover.classList.add('interactive');
            cover.setAttribute('role', 'button');
            cover.setAttribute('tabindex', '0');
            cover.setAttribute('title', '更换朋友圈背景图');
            cover.setAttribute('aria-label', '更换朋友圈背景图');
            cover.addEventListener('click', event => {
                if (document.body.classList.contains('edit-mode')) return;
                event.preventDefault();
                event.stopPropagation();
                getPrivateMomentsCoverInput().click();
            });
            cover.addEventListener('keydown', event => {
                if (event.key !== 'Enter' && event.key !== ' ') return;
                event.preventDefault();
                getPrivateMomentsCoverInput().click();
            });
        });
        loadPrivateMomentsCoverImage();
    }

    const privateContactHomepageCoverPrefix = 'private_contact_homepage_cover:';
    const privateContactHomepageCoverLocalPrefix = 'rinno:private:contact-homepage-cover:';
    let privateContactHomepageCoverTarget = '';

    function getPrivateContactHomepageCoverStorageId(contactId) {
        return privateContactHomepageCoverPrefix + String(contactId || '');
    }

    function getPrivateContactHomepageCoverLocalKey(contactId) {
        return privateContactHomepageCoverLocalPrefix + String(contactId || '');
    }

    function applyPrivateContactHomepageCoverImage(contactId, content) {
        if (!contactId) return;
        document.querySelectorAll(`.private-contact-homepage-cover[data-private-contact-homepage-cover="${contactId}"]`).forEach(cover => {
            if (content) {
                cover.style.setProperty('--private-contact-homepage-cover-image', `url("${content}")`);
                cover.style.setProperty('background-image', `url("${content}")`);
                cover.style.setProperty('background-size', 'cover');
                cover.style.setProperty('background-position', 'center center');
                cover.style.setProperty('background-repeat', 'no-repeat');
                cover.classList.add('has-custom-cover');
            } else {
                const hasExistingInlineImage = Boolean(cover.style.backgroundImage && cover.style.backgroundImage !== 'none');
                const hasExistingVariable = Boolean(cover.style.getPropertyValue('--private-contact-homepage-cover-image').trim());
                const alreadyCustom = cover.classList.contains('has-custom-cover');
                if (hasExistingInlineImage || hasExistingVariable || alreadyCustom) return;
                cover.style.removeProperty('--private-contact-homepage-cover-image');
                cover.style.removeProperty('background-image');
                cover.style.removeProperty('background-size');
                cover.style.removeProperty('background-position');
                cover.style.removeProperty('background-repeat');
                cover.classList.remove('has-custom-cover');
            }
        });
    }

    async function loadPrivateContactHomepageCoverImage(contactId) {
        if (!contactId) return;
        let content = '';
        try {
            if (typeof db !== 'undefined' && db?.edits) {
                const saved = await db.edits.get(getPrivateContactHomepageCoverStorageId(contactId));
                content = String(saved?.content || '');
            }
        } catch (error) {
            console.warn('Private contact homepage cover load skipped:', error);
        }
        if (!content) {
            try {
                content = window.localStorage?.getItem(getPrivateContactHomepageCoverLocalKey(contactId)) || '';
            } catch (error) {
                content = '';
            }
        }
        if (!content) return;
        applyPrivateContactHomepageCoverImage(contactId, content);
    }

    async function savePrivateContactHomepageCoverImage(contactId, content) {
        if (!contactId) return;
        try {
            window.localStorage?.setItem(getPrivateContactHomepageCoverLocalKey(contactId), content);
        } catch (error) {
            console.warn('Private contact homepage cover local fallback skipped:', error);
        }
        try {
            if (typeof db !== 'undefined' && db?.edits) {
                await db.edits.put({
                    id: getPrivateContactHomepageCoverStorageId(contactId),
                    content,
                    type: 'image'
                });
            }
        } catch (error) {
            console.warn('Private contact homepage cover save skipped:', error);
        }
    }

    function getPrivateContactHomepageCoverInput() {
        let input = document.getElementById('private-contact-homepage-cover-input');
        if (input) return input;
        input = document.createElement('input');
        input.id = 'private-contact-homepage-cover-input';
        input.type = 'file';
        input.accept = 'image/*';
        input.hidden = true;
        input.addEventListener('change', async event => {
            const file = event.target.files?.[0];
            const contactId = privateContactHomepageCoverTarget;
            privateContactHomepageCoverTarget = '';
            event.target.value = '';
            if (!file || !contactId) return;
            try {
                const content = await readPrivateCoverFile(file);
                if (!content) return;
                applyPrivateContactHomepageCoverImage(contactId, content);
                await savePrivateContactHomepageCoverImage(contactId, content);
                if (typeof window.showPrivateSystemToast === 'function') window.showPrivateSystemToast('角色主页背景图已保存。');
            } catch (error) {
                console.error('Private contact homepage cover update failed:', error);
                if (typeof window.showPrivateSystemToast === 'function') window.showPrivateSystemToast('背景图保存失败，请换一张图片。');
            }
        });
        document.body.appendChild(input);
        return input;
    }

